section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/deploy-notes-template-with-rollback.json",
  "title": "Deploy Notes Template with Rollback",
  "type": "object",
  "required": [
    "artefact_id",
    "deployable_id",
    "blast_radius",
    "rollback_recipe",
    "verification_steps",
    "rollback_window",
    "operator",
    "last_touched",
    "template_version",
    "status"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "deployable_id": {
      "type": "string",
      "minLength": 7,
      "description": "git SHA, image digest, or semver tag"
    },
    "blast_radius": {
      "type": "array",
      "minItems": 1,
      "description": "list of impacted surfaces"
    },
    "rollback_recipe": {
      "type": "string",
      "minLength": 1,
      "description": "one-line rollback procedure"
    },
    "verification_steps": {
      "type": "array",
      "minItems": 2,
      "description": "list of step objects {action, pass_criterion}"
    },
    "rollback_window": {
      "type": "string",
      "description": "ISO-8601 duration or 'forever'"
    },
    "operator": {
      "type": "string",
      "description": "required field operator",
      "minLength": 1
    }
  },
  "additionalProperties": false
}
